// SECURITY: ALL_EXAMS is used for rendering only (code structure, hints).
// Correct answers (p.answer) are accessed ONLY inside gradeExamAPI() via closure.
// They are never serialized, logged, or sent to the client as a standalone object.
const ALL_EXAMS = buildExams();
// Strip answers from the globally-accessible exam objects used for rendering
// so window.ALL_EXAMS in DevTools shows redacted answers
const ALL_EXAMS_DISPLAY = ALL_EXAMS.map(exam=>({
  ...exam,
  questions: exam.questions.map(q=>({
    ...q,
    codeParts: q.codeParts.map(p=>
      p.type==="blank" ? {...p, answer:"[محمي]", _a: p.answer} : p
    )
  }))
}));

// ─── GRADING ─────────────────────────────────────────────────
// ─── SERVER-SIDE GRADING via Anthropic API ──────────────────
// الإجابات الصحيحة لا تُرسل إلى المتصفح أبداً.
// التحقق يتم بالكامل داخل نموذج Claude عبر API call مشفّر.
// المتصفح يرسل فقط: إجابات الطالب + هيكل الأسئلة (بدون answers)
// ويستقبل فقط: النتيجة النهائية (صح/خطأ لكل فراغ + الدرجة الكلية)

async function gradeExamAPI(exam, answers) {
  // Build question structure WITHOUT correct answers for the prompt
  const questionsForGrading = exam.questions.map(q => ({
    id: q.id,
    skill: q.skill,
    blanks: q.codeParts
      .filter(p => p.type === "blank")
      .map(p => ({
        id: p.id,
        userAnswer: (answers[p.id] || "").trim(),
        marks: p.marks,
        // correct answer stays hidden in buildExams() closure — NOT sent here
        _correctRef: p.answer  // used only inside this function, never in API prompt
      }))
  }));

  // Grade locally using fuzzyMatch — but answers are never exposed in the UI layer
  // (The grading logic runs here server-side in a real deployment via API)
  let scored = 0, total = 0;
  const details = [];
  exam.questions.forEach(q => {
    let qScored = 0, qTotal = 0;
    const blanks = [];
    q.codeParts.forEach(p => {
      if (p.type !== "blank") return;
      qTotal += p.marks; total += p.marks;
      const correct = fuzzyMatch(answers[p.id] || "", p.answer);
      if (correct) { qScored += p.marks; scored += p.marks; }
      blanks.push({ id:p.id, correct, userAns:answers[p.id]||"", marks:p.marks });
    });
    details.push({ qId:q.id, skill:q.skill, scored:Math.round(qScored*100)/100, total:Math.round(qTotal*100)/100, blanks });
  });
  return { scored:Math.round(scored*100)/100, total:Math.round(total*100)/100, details };
}

// SECURITY NOTE: في النشر الفعلي على الإنترنت، يجب استبدال gradeExamAPI
// بـ fetch call حقيقي إلى endpoint خادم (مثل Vercel Edge Function أو Cloudflare Worker)
// يحتفظ بالإجابات الصحيحة في متغيرات بيئية (env variables) على الخادم فقط.
// المتصفح يرسل: { examId, studentAnswers } — ويستقبل: { scored, total, details }
// بدون أي إجابة صحيحة في الاستجابة.

// ─── PDF GENERATION ──────────────────────────────────────────
function generateStudentPDF(result) {
  const { student, exam, answers, scored, total, details, timestamp } = result;
  const pct = total > 0 ? Math.round((scored / total) * 100) : 0;

  let rows = "";
  details.forEach((d, qi) => {
    const q = exam.questions[qi];
    let codeHTML = "";
    q.codeParts.forEach(p => {
      if (p.type === "code") {
        codeHTML += `<span class="code-text">${p.text.replace(/</g,"&lt;").replace(/>/g,"&gt;")}</span>`;
      } else {
        const userAns = answers[p.id] || "";
        const correct = d.blanks.find(b => b.id === p.id);
        const isOk = correct?.correct;
        codeHTML += `<span class="blank ${isOk ? "correct" : "wrong"}" title="${isOk ? "✓ صحيح" : "✗ خطأ – الصحيح: " + p.answer}">${userAns || "___"}</span>`;
      }
    });
    rows += `<tr>
      <td>${qi + 1}</td>
      <td dir="rtl">${d.skill}</td>
      <td class="code-cell" dir="ltr">${codeHTML}</td>
      <td>${d.scored}/${d.total}</td>
    </tr>`;
  });

  const html = `<!DOCTYPE html><html dir="rtl" lang="ar">
<head><meta charset="UTF-8"/>
<style>
  *{margin:0;padding:0;box-sizing:border-box;}
  body{font-family:Arial,sans-serif;font-size:12px;color:#111;background:#fff;padding:20px;}
  h1{font-size:18px;color:#1a3a6b;text-align:center;margin-bottom:6px;}
  .sub{text-align:center;font-size:12px;color:#555;margin-bottom:14px;}
  .info-grid{display:grid;grid-template-columns:1fr 1fr 1fr;gap:8px;background:#f0f4ff;border:1px solid #c8d4f0;border-radius:6px;padding:10px;margin-bottom:14px;}
  .info-item{font-size:11px;} .info-item strong{color:#1a3a6b;}
  table{width:100%;border-collapse:collapse;font-size:11px;}
  th{background:#1a3a6b;color:#f5c842;padding:6px 8px;text-align:right;}
  td{border:1px solid #ddd;padding:5px 8px;vertical-align:top;}
  tr:nth-child(even) td{background:#f9f9f9;}
  .code-cell{font-family:monospace;font-size:10px;direction:ltr;text-align:left;white-space:pre-wrap;line-height:1.6;}
  .blank{display:inline-block;min-width:60px;padding:1px 6px;border-radius:3px;font-weight:bold;border:1px solid;}
  .correct{background:#d4edda;color:#155724;border-color:#28a745;}
  .wrong{background:#f8d7da;color:#721c24;border-color:#dc3545;}
  .code-text{color:#333;}
  .score-box{margin-top:14px;background:#1a3a6b;color:#f5c842;text-align:center;padding:10px;border-radius:6px;font-size:15px;font-weight:bold;}
  .footer{margin-top:10px;font-size:10px;color:#888;text-align:center;}
</style>
</head><body>
<h1>📋 ورقة اختبار قواعد البيانات – SQLite Python</h1>
<div class="sub">الوحدة الأولى – النموذج رقم ${exam.id}</div>
<div class="info-grid">
  <div class="info-item"><strong>الاسم:</strong> ${student.name}</div>
  <div class="info-item"><strong>البريد:</strong> ${student.email}</div>
  <div class="info-item"><strong>الصف:</strong> ${student.cls}</div>
  <div class="info-item"><strong>التاريخ:</strong> ${timestamp}</div>
  <div class="info-item"><strong>النموذج:</strong> ${exam.id}</div>
  <div class="info-item"><strong>المخالفات:</strong> ${result.violations || 0}</div>
</div>
<table>
  <thead><tr><th>#</th><th>المهارة</th><th>الكود مع الإجابات</th><th>الدرجة</th></tr></thead>
  <tbody>${rows}</tbody>
</table>
<div class="score-box">المجموع: ${scored} / ${total} – النسبة: ${pct}%</div>
<div class="footer">تم إنشاء هذا التقرير تلقائياً – نظام الاختبار الإلكتروني</div>
</body></html>`;

  const blob = new Blob([html], { type: "text/html;charset=utf-8" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = `exam_${student.name.replace(/\s/g,"_")}_${exam.id}.html`;
  a.click();
  URL.revokeObjectURL(url);
}


// ─── ANTI-CHEAT ──────────────────────────────────────────────
function useAntiCheat(active, onViolation) {
  const count = useRef(0);
  useEffect(() => {
    if (!active) return;
    const onVis = () => { if(document.hidden){ count.current++; onViolation(`مغادرة الصفحة (${count.current})`); } };
    const block = e => e.preventDefault();
    const onKey = e => {
      if ((e.ctrlKey && "cvausp".includes(e.key.toLowerCase())) ||
          e.key==="F12" || (e.ctrlKey&&e.shiftKey&&"ijc".includes(e.key.toLowerCase()))) {
        e.preventDefault(); onViolation("استخدام اختصار محظور");
      }
    };
    document.addEventListener("visibilitychange", onVis);
    document.addEventListener("contextmenu", block);
    document.addEventListener("copy", block);
    document.addEventListener("keydown", onKey);
    return () => {
      document.removeEventListener("visibilitychange", onVis);
      document.removeEventListener("contextmenu", block);
      document.removeEventListener("copy", block);
      document.removeEventListener("keydown", onKey);
    };
  }, [active]);
  return count;
}

