// ─── TIMER ───────────────────────────────────────────────────
function Timer({ seconds, onExpire }) {
  const [rem, setRem] = useState(seconds);
  useEffect(() => {
    if (rem<=0){ onExpire(); return; }
    const t = setTimeout(()=>setRem(r=>r-1),1000);
    return ()=>clearTimeout(t);
  },[rem]);
  const m = Math.floor(rem/60).toString().padStart(2,"0");
  const s = (rem%60).toString().padStart(2,"0");
  const urgent = rem < 120;
  return (
    <div style={{display:"flex",alignItems:"center",gap:8,
      background:urgent?"#fff0f0":T.goldLight,
      border:`2px solid ${urgent?"#e53e3e":T.gold}`,
      borderRadius:12,padding:"6px 14px"}}>
      <span style={{fontSize:11,color:T.muted,fontFamily:"Cairo"}}>الوقت المتبقي</span>
      <span style={{fontSize:22,fontWeight:900,color:urgent?"#e53e3e":T.goldDark,fontFamily:"monospace",letterSpacing:2}}>
        {m}:{s}
      </span>
    </div>
  );
}

