// ─── QUESTION EDITOR ─────────────────────────────────────────
function QuestionEditor({ customQuestions, onSave, onClose }) {
  const [raw, setRaw] = useState(customQuestions ? JSON.stringify(customQuestions, null, 2) : "");
  const [error, setError] = useState("");
  const placeholder = JSON.stringify([{
    id:"q1", skill:"اسم المهارة", instruction:"تعليمات السؤال",
    marks:1, codeParts:[
      {type:"code",text:"import sqlite3\ncur.execute('''\n    "},
      {type:"blank",id:"b1",answer:"CREATE TABLE",hint:"تلميح",marks:0.5},
      {type:"code",text:" IF NOT EXISTS ...''')"}
    ]
  }], null, 2);
  const handleSave = () => {
    try {
      const parsed = JSON.parse(raw);
      if (!Array.isArray(parsed)) throw new Error("يجب أن يكون مصفوفة");
      onSave(parsed);
      setError("");
    } catch(e) { setError("خطأ في صيغة JSON: " + e.message); }
  };
  return (
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.6)",zIndex:1000,display:"flex",alignItems:"center",justifyContent:"center",padding:16}}>
      <div className="card" style={{width:"100%",maxWidth:800,maxHeight:"90vh",display:"flex",flexDirection:"column",padding:24}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:16}}>
          <h3 style={{fontSize:18,fontWeight:900,color:T.goldDark}}>✏️ تعديل الأسئلة (JSON)</h3>
          <button className="btn-outline-gold" onClick={onClose}>✕ إغلاق</button>
        </div>
        <p style={{fontSize:12,color:T.muted,marginBottom:12,lineHeight:1.8}}>
          أدخلي/أدخل مصفوفة JSON تحتوي على الأسئلة. كل سؤال يحتوي: id, skill, instruction, marks, codeParts.
          <br/>كل blank يحتوي: type:"blank", id, answer, hint, marks.
        </p>
        {error&&<div style={{color:T.red,fontSize:12,marginBottom:8,padding:"8px 12px",background:"#fff5f5",borderRadius:8}}>{error}</div>}
        <textarea value={raw||placeholder} onChange={e=>setRaw(e.target.value)}
          style={{flex:1,minHeight:320,fontFamily:"monospace",fontSize:12,border:`1.5px solid ${T.border}`,
            borderRadius:10,padding:14,background:"#fafaf0",resize:"none",outline:"none",direction:"ltr"}}/>
        <div style={{display:"flex",gap:10,marginTop:16,justifyContent:"flex-end"}}>
          <button className="btn-gold" onClick={handleSave}>💾 حفظ الأسئلة</button>
          <button className="btn-outline-gold" onClick={()=>setRaw("")}>🗑️ مسح</button>
        </div>
      </div>
    </div>
  );
}

// ─── STATS MODAL ─────────────────────────────────────────────
function StatsModal({results, onClose}) {
  const ALL_CLASSES_LOCAL=["الكل",...new Set(results.map(r=>r.student.cls))];
  const total=results.length;
  const avg=total?(results.reduce((s,r)=>s+r.scored,0)/total).toFixed(2):0;
  const passCount=results.filter(r=>(r.scored/r.total)*100>=60).length;
  const passPct=total?Math.round((passCount/total)*100):0;

  // Per-class breakdown
  const clsMap={};
  results.forEach(r=>{
    const c=r.student.cls||"غير محدد";
    if(!clsMap[c]) clsMap[c]={total:0,pass:0};
    clsMap[c].total++;
    if((r.scored/r.total)*100>=60) clsMap[c].pass++;
  });

  // Performance tiers
  const weak=results.filter(r=>(r.scored/r.total)*100<50).length;
  const mid=results.filter(r=>{const p=(r.scored/r.total)*100; return p>=50&&p<75;}).length;
  const excel=results.filter(r=>(r.scored/r.total)*100>=75).length;
  const maxTier=Math.max(weak,mid,excel,1);

  return (
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.6)",zIndex:2000,display:"flex",alignItems:"flex-start",justifyContent:"center",padding:"20px 16px",overflowY:"auto"}}>
      <div className="card" style={{width:"100%",maxWidth:560,padding:0,overflow:"hidden",marginBottom:20}}>
        {/* Header */}
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"16px 20px",borderBottom:`2px solid ${T.border}`}}>
          <button onClick={onClose} style={{background:"none",border:"none",cursor:"pointer",fontSize:18,color:T.muted,fontFamily:"Cairo",fontWeight:700,padding:"2px 8px"}}>✕</button>
          <div style={{fontSize:17,fontWeight:900,color:T.goldDark,fontFamily:"Cairo"}}>📊 الإحصائيات التفصيلية</div>
        </div>
        <div style={{padding:20}}>
          {/* Top 3 metrics */}
          <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:10,marginBottom:20}}>
            {[
              {v:parseFloat(avg),l:"متوسط الدرجات",c:"#e07b39"},
              {v:`${passPct}%`,l:"نسبة النجاح",c:T.green},
              {v:total,l:"إجمالي الطلاب",c:T.navy},
            ].map((s,i)=>(
              <div key={i} style={{background:"#f8f8f8",border:`1px solid ${T.border}`,borderRadius:12,padding:"14px 10px",textAlign:"center"}}>
                <div style={{fontSize:26,fontWeight:900,color:s.c,fontFamily:"Cairo"}}>{s.v}</div>
                <div style={{fontSize:11,color:T.muted,fontFamily:"Cairo",marginTop:4}}>{s.l}</div>
              </div>
            ))}
          </div>

          {/* Class distribution */}
          <div style={{marginBottom:20}}>
            <div style={{fontSize:14,fontWeight:700,color:T.goldDark,fontFamily:"Cairo",marginBottom:12,textAlign:"right"}}>توزيع النتائج حسب الفصل:</div>
            {Object.entries(clsMap).map(([cls,data],i)=>{
              const pct=data.total?Math.round((data.pass/data.total)*100):0;
              const c=pct>=75?T.green:pct>=50?"#e07b39":T.red;
              return (
                <div key={i} style={{display:"flex",alignItems:"center",gap:10,marginBottom:8,direction:"rtl"}}>
                  <span style={{fontSize:12,fontFamily:"Cairo",color:T.text,minWidth:80,textAlign:"right"}}>{cls}</span>
                  <div style={{flex:1,background:"#eee",borderRadius:99,height:12,overflow:"hidden"}}>
                    <div style={{width:`${pct}%`,height:"100%",background:c,borderRadius:99,transition:"width 0.5s"}}/>
                  </div>
                  <span style={{fontSize:12,fontWeight:700,color:c,minWidth:36,fontFamily:"Cairo",textAlign:"left"}}>{pct}%</span>
                </div>
              );
            })}
            {Object.keys(clsMap).length===0&&(
              <div style={{textAlign:"center",color:T.muted,fontFamily:"Cairo",fontSize:13,padding:"20px 0"}}>لا توجد نتائج بعد</div>
            )}
          </div>

          {/* Performance tiers */}
          <div>
            <div style={{fontSize:14,fontWeight:700,color:T.goldDark,fontFamily:"Cairo",marginBottom:12,textAlign:"right"}}>توزيع مستويات الأداء:</div>
            {[
              {label:"ضعيف (< 50%)",count:weak,color:T.red},
              {label:"متوسط (50-75%)",count:mid,color:"#e07b39"},
              {label:"ممتاز (≥ 75%)",count:excel,color:T.green},
            ].map((tier,i)=>(
              <div key={i} style={{display:"flex",alignItems:"center",gap:10,marginBottom:10,direction:"rtl"}}>
                <span style={{fontSize:12,fontFamily:"Cairo",color:T.text,minWidth:110,textAlign:"right"}}>{tier.label}</span>
                <div style={{flex:1,background:"#eee",borderRadius:99,height:14,overflow:"hidden"}}>
                  <div style={{width:`${(tier.count/maxTier)*100}%`,height:"100%",background:tier.color,borderRadius:99,transition:"width 0.5s"}}/>
                </div>
                <span style={{fontSize:14,fontWeight:900,color:tier.color,minWidth:28,fontFamily:"Cairo",textAlign:"left"}}>{tier.count}</span>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}

